+export interface StorageApi {
+  keys(): readonly string[];
+  get<T>(key: string, defaultValue?: T): T | undefined;
+  set<T>(key: string, value: T): Promise<void>;
+}
+
+export interface EventsApi {
+  emit<T = unknown>(name: string, payload: T): void;
+}
