+export interface Range {
+  start: Position;
+  end: Position;
+}
+
+export interface Position {
+  line: number;
+  character: number;
+}
+
+export type ExtensionActivate<T> = () => T | (T & Disposable) | Promise<T> | Promise<T & Disposable>;
