+      panel.title = title.trim();
+    }
+  });
+
+  return createDisposable(() => {
+    for (const panel of terminalPanels.values()) {
+      panel[Symbol.dispose]();
+    }
+    terminalPanels.clear();
+    return [...disposables];
+  });
+});

